mapper.select:
SELECT id, session_id, from_user, from_role, type, content,
       signature, reply_to_id, recalled, recalled_at, recalled_by, created_at
FROM chat_message
WHERE session_id = #{sessionId}
  AND (deleted = 0 OR deleted IS NULL)

    AND created_at >= #{startTime}


    AND created_at <= #{endTime}

ORDER BY created_at ASC, id ASC
LIMIT 1000
